/**
 * Pure validation functions for user operations.
 *
 * These functions contain no side effects and no database calls.
 * They accept pre-fetched data and validate business rules.
 */

import type { User } from '../models/user.js';

/**
 * Validate that a user exists, throwing if not.
 */
export function validateUserExists(
  user: User | undefined,
  id: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${id}`);
  }
}

/**
 * Validate that an email is not already taken when creating a user.
 */
export function validateEmailNotTaken(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not already in use when updating a user.
 * Only checks if the email is actually changing.
 */
export function validateEmailNotTakenForUpdate(
  newEmail: string,
  currentEmail: string,
  existingUser: User | undefined,
): void {
  if (newEmail !== currentEmail && existingUser) {
    throw new Error(`Email ${newEmail} is already in use`);
  }
}

/**
 * Pure validation functions for order operations.
 *
 * These functions contain no side effects and no database calls.
 * They accept pre-fetched data and validate business rules.
 */

import type { Order, OrderItem, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';

/**
 * Validate that a user exists (for order creation).
 */
export function validateOrderUserExists(
  user: User | undefined,
  userId: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that an order has at least one item.
 */
export function validateOrderHasItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Validate that an order exists.
 */
export function validateOrderExists(
  order: Order | undefined,
  id: string,
): asserts order is Order {
  if (!order) {
    throw new Error(`Order not found: ${id}`);
  }
}

/**
 * Allowed status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that a status transition is allowed, throwing if not.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Pure validation functions for notification preferences.
 *
 * These functions contain no side effects and no database calls.
 * They accept pre-fetched data and validate business rules.
 */

import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { NOTIFICATION_TYPE_TO_CATEGORY } from '../models/user-preferences.js';

/**
 * Determine whether an email notification should be sent based on user preferences.
 *
 * Returns true if:
 * - Preferences are undefined (defaults allow all notifications)
 * - Email is enabled AND the category for the notification type is enabled
 *
 * Returns false if:
 * - Email is globally disabled
 * - The specific category is disabled
 */
export function shouldSendEmailForPreferences(
  preferences: UserPreferences | undefined,
  notificationType: NotificationType,
): boolean {
  // No preferences set — default is to send all notifications
  if (!preferences) {
    return true;
  }

  // Master switch
  if (!preferences.email.enabled) {
    return false;
  }

  // Category check
  const categoryKey = NOTIFICATION_TYPE_TO_CATEGORY[notificationType];
  if (!preferences.email.categories[categoryKey]) {
    return false;
  }

  return true;
}

