import { describe, it, expect } from 'vitest';
import {
  validateUserExists,
  validateEmailNotTaken,
  validateEmailNotTakenForUpdate,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user.validator', () => {
  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      expect(() => validateUserExists(makeUser(), 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-0001')).toThrow(
        'User not found: user-0001',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when no existing user with that email', () => {
      expect(() =>
        validateEmailNotTaken('new@example.com', undefined),
      ).not.toThrow();
    });

    it('should throw when a user with that email exists', () => {
      expect(() =>
        validateEmailNotTaken('alice@example.com', makeUser()),
      ).toThrow('User with email alice@example.com already exists');
    });
  });

  describe('validateEmailNotTakenForUpdate', () => {
    it('should not throw when email is unchanged', () => {
      expect(() =>
        validateEmailNotTakenForUpdate(
          'alice@example.com',
          'alice@example.com',
          makeUser(),
        ),
      ).not.toThrow();
    });

    it('should not throw when new email is not taken', () => {
      expect(() =>
        validateEmailNotTakenForUpdate(
          'new@example.com',
          'alice@example.com',
          undefined,
        ),
      ).not.toThrow();
    });

    it('should throw when new email is taken by another user', () => {
      expect(() =>
        validateEmailNotTakenForUpdate(
          'bob@example.com',
          'alice@example.com',
          makeUser({ email: 'bob@example.com' }),
        ),
      ).toThrow('Email bob@example.com is already in use');
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateOrderUserExists,
  validateOrderHasItems,
  validateOrderExists,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

const makeUser = (): User => ({
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
});

const makeOrder = (overrides: Partial<Order> = {}): Order => ({
  id: 'order-0001',
  userId: 'user-0001',
  items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
  total: 10,
  status: 'pending',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('order.validator', () => {
  describe('validateOrderUserExists', () => {
    it('should not throw when user exists', () => {
      expect(() => validateOrderUserExists(makeUser(), 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateOrderUserExists(undefined, 'user-0001')).toThrow(
        'User not found: user-0001',
      );
    });
  });

  describe('validateOrderHasItems', () => {
    it('should not throw when items are present', () => {
      expect(() =>
        validateOrderHasItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('validateOrderExists', () => {
    it('should not throw when order exists', () => {
      expect(() => validateOrderExists(makeOrder(), 'order-0001')).not.toThrow();
    });

    it('should throw when order is undefined', () => {
      expect(() => validateOrderExists(undefined, 'order-0001')).toThrow(
        'Order not found: order-0001',
      );
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import { shouldSendEmailForPreferences } from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../../src/models/user-preferences.js';

const makePreferences = (
  overrides: Partial<UserPreferences> = {},
): UserPreferences => ({
  id: 'pref-0001',
  userId: 'user-0001',
  email: { ...DEFAULT_EMAIL_PREFERENCES, categories: { ...DEFAULT_EMAIL_PREFERENCES.categories } },
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('preferences.validator', () => {
  describe('shouldSendEmailForPreferences', () => {
    it('should return true when preferences are undefined', () => {
      expect(shouldSendEmailForPreferences(undefined, 'order:confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is enabled', () => {
      const prefs = makePreferences();
      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: { ...DEFAULT_EMAIL_PREFERENCES.categories },
          enabled: false,
        },
      });
      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(false);
    });

    it('should return false when specific category is disabled', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: {
            ...DEFAULT_EMAIL_PREFERENCES.categories,
            orderConfirmations: false,
          },
        },
      });
      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(false);
    });

    it('should return true for enabled category even if another is disabled', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: {
            ...DEFAULT_EMAIL_PREFERENCES.categories,
            orderConfirmations: false,
          },
        },
      });
      expect(shouldSendEmailForPreferences(prefs, 'order:status-update')).toBe(true);
    });

    it('should check each notification type against its category', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: {
            orderConfirmations: true,
            orderStatusUpdates: false,
            welcomeMessages: true,
            profileUpdates: false,
          },
        },
      });

      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(true);
      expect(shouldSendEmailForPreferences(prefs, 'order:status-update')).toBe(false);
      expect(shouldSendEmailForPreferences(prefs, 'user:welcome')).toBe(true);
      expect(shouldSendEmailForPreferences(prefs, 'user:profile-updated')).toBe(false);
    });
  });
});

