+/**
+ * Pure validation functions for notification preferences.
+ *
+ * These functions contain no side effects and no database calls.
+ * They accept pre-fetched data and validate business rules.
+ */
+
+import type { UserPreferences } from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { NOTIFICATION_TYPE_TO_CATEGORY } from '../models/user-preferences.js';
+
+/**
+ * Determine whether an email notification should be sent based on user preferences.
+ *
+ * Returns true if:
+ * - Preferences are undefined (defaults allow all notifications)
+ * - Email is enabled AND the category for the notification type is enabled
+ *
+ * Returns false if:
+ * - Email is globally disabled
+ * - The specific category is disabled
+ */
+export function shouldSendEmailForPreferences(
+  preferences: UserPreferences | undefined,
+  notificationType: NotificationType,
+): boolean {
+  // No preferences set — default is to send all notifications
+  if (!preferences) {
+    return true;
+  }
+
+  // Master switch
+  if (!preferences.email.enabled) {
+    return false;
+  }
+
+  // Category check
+  const categoryKey = NOTIFICATION_TYPE_TO_CATEGORY[notificationType];
+  if (!preferences.email.categories[categoryKey]) {
+    return false;
+  }
+
+  return true;
+}

