+/**
+ * Pure validation functions for user operations.
+ *
+ * These functions contain no side effects and no database calls.
+ * They accept pre-fetched data and validate business rules.
+ */
+
+import type { User } from '../models/user.js';
+
+/**
+ * Validate that a user exists, throwing if not.
+ */
+export function validateUserExists(
+  user: User | undefined,
+  id: string,
+): asserts user is User {
+  if (!user) {
+    throw new Error(`User not found: ${id}`);
+  }
+}
+
+/**
+ * Validate that an email is not already taken when creating a user.
+ */
+export function validateEmailNotTaken(
+  email: string,
+  existingUser: User | undefined,
+): void {
+  if (existingUser) {
+    throw new Error(`User with email ${email} already exists`);
+  }
+}
+
+/**
+ * Validate that an email is not already in use when updating a user.
+ * Only checks if the email is actually changing.
+ */
+export function validateEmailNotTakenForUpdate(
+  newEmail: string,
+  currentEmail: string,
+  existingUser: User | undefined,
+): void {
+  if (newEmail !== currentEmail && existingUser) {
+    throw new Error(`Email ${newEmail} is already in use`);
+  }
+}

